const { execSync } = require('child_process');
const item = $input.item.json;
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;
const cwd = 'C:/Users/veeramani/desktop/playwright-mcp';

function extractJSON(str) {
  const firstOpen = str.indexOf('{');
  const lastClose = str.lastIndexOf('}');
  if (firstOpen !== -1 && lastClose !== -1 && lastClose > firstOpen) {
    return JSON.parse(str.substring(firstOpen, lastClose + 1));
  }
  throw new Error('No JSON found in output');
}

const startTime = Date.now();
try {
  const stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 300000 }).toString();
  const report = extractJSON(stdout);
  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  return { json: { 
    ...item, 
    exitCode: 0, 
    status: 'passed', 
    duration: `${duration}s`, 
    casesTotal: report.stats.expected + report.stats.unexpected + report.stats.skipped,
    casesPassed: report.stats.expected,
    casesFailed: report.stats.unexpected,
    casesSkipped: report.stats.skipped
  } };
} catch (e) {
  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  let casesTotal = 0, casesPassed = 0, casesFailed = 0, casesSkipped = 0;
  try {
    const report = extractJSON(e.stdout.toString());
    casesTotal = report.stats.expected + report.stats.unexpected + report.stats.skipped;
    casesPassed = report.stats.expected;
    casesFailed = report.stats.unexpected;
    casesSkipped = report.stats.skipped;
  } catch (parseErr) {}

  return { json: { 
    ...item, 
    exitCode: e.status || 1, 
    status: 'failed', 
    duration: `${duration}s`, 
    casesTotal, 
    casesPassed, 
    casesFailed, 
    casesSkipped,
    stderr: (e.stderr || e.message || '').toString() 
  } };
}

