const fs = require('fs');
const path = require('path');
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
const lockFile = path.join(resultsDir, 'summary.lock');

// 🔒 ONE-TIME LOCK LOGIC
if (fs.existsSync(lockFile)) return { json: { alreadySent: true } };
fs.writeFileSync(lockFile, 'locked');

const files = fs.readdirSync(resultsDir).filter(f => f.endsWith('.json'));
let totalFiles = 0, passedFiles = 0, totalCases = 0, passedCases = 0, totalDuration = 0, product = 'ERP';
let failures = [];

files.forEach(file => {
  const data = JSON.parse(fs.readFileSync(path.join(resultsDir, file)));
  totalFiles++; 
  if (data.exitCode === 0) {
    passedFiles++;
  } else {
    failures.push(data.filename);
  }

  totalCases += (data.casesTotal || 0);
  passedCases += (data.casesPassed || 0);

  product = data.product || product;
  const d = parseFloat(data.duration || '0');
  if (!isNaN(d)) totalDuration += d;
});

return { json: {
  alreadySent: false, 
  totalFiles,
  passedFiles,
  totalCases,
  passedCases,
  failedCases: totalCases - passedCases,
  failedFiles: failures.length > 0 ? failures.join(', ') : 'None',
  product, 
  successRate: totalCases > 0 ? ((passedCases/totalCases)*100).toFixed(2) + '%' : '0.00%',
  totalDuration: totalDuration.toFixed(2) + 's',
  timestamp: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })
} };
